<content>#!/usr/bin/env python3
"""
Simple test script for WebSocket server
Runs basic connectivity and functionality tests
"""

import asyncio
import sys
import time
from src.websocket_client import WebSocketClient


async def run_tests():
    """Run comprehensive WebSocket tests"""

    print("=" * 60)
    print("WebSocket Server Test Suite")
    print("=" * 60)

    client = WebSocketClient("ws://localhost:8765")

    # Test 1: Connection
    print("\n[Test 1] Connection Test")
    print("-" * 60)
    if await client.connect():
        print("✓ Successfully connected to WebSocket server")
    else:
        print("✗ Failed to connect to WebSocket server")
        print("\nMake sure the server is running:")
        print("  python src/websocket_server.py")
        return False

    await asyncio.sleep(0.5)

    # Test 2: Ping/Pong
    print("\n[Test 2] Ping/Pong Test")
    print("-" * 60)
    pong = await client.send_ping()
    if pong and pong.get("type") == "pong":
        print(f"✓ Received pong: {pong.get('timestamp')}")
    else:
        print("✗ Ping/pong failed")
        return False

    await asyncio.sleep(0.5)

    # Test 3: Statistics Request
    print("\n[Test 3] Statistics Request Test")
    print("-" * 60)
    stats = await client.request_stats()
    if stats and stats.get("type") == "stats":
        print("✓ Received statistics:")
        data = stats.get("data", {})
        print(f"  - Total Requests: {data.get('total_requests', 0)}")
        print(f"  - Successful Routes: {data.get('successful_routes', 0)}")
        print(f"  - Failed Routes: {data.get('failed_routes', 0)}")
        print(f"  - Connected Clients: {stats.get('connected_clients', 0)}")
    else:
        print("✗ Statistics request failed")
        return False

    await asyncio.sleep(0.5)

    # Test 4: Routing Requests
    print("\n[Test 4] Routing Request Tests")
    print("-" * 60)

    test_queries = [
        ("Simple query", "What is 2+2?"),
        ("Complex query", "Explain the theory of relativity in simple terms"),
        ("Code query", "Write a Python function to sort a list"),
    ]

    for test_name, query in test_queries:
        print(f"\n  Testing: {test_name}")
        result = await client.send_route_request(query)

        if result and result.get("type") == "routing_result":
            print(f"  ✓ Query routed to: {result.get('result')}")
        else:
            print(f"  ✗ Routing failed for: {test_name}")
            return False

        await asyncio.sleep(0.5)

    # Test 5: Final Statistics
    print("\n[Test 5] Final Statistics Check")
    print("-" * 60)
    final_stats = await client.request_stats()
    if final_stats and final_stats.get("type") == "stats":
        data = final_stats.get("data", {})
        print("✓ Final statistics:")
        print(f"  - Total Requests: {data.get('total_requests', 0)}")
        print(f"  - Successful Routes: {data.get('successful_routes', 0)}")
        print(f"  - Failed Routes: {data.get('failed_routes', 0)}")

    # Close connection
    await client.close()

    print("\n" + "=" * 60)
    print("All tests passed! ✓")
    print("=" * 60)

    return True


async def load_test(num_clients=10, num_requests=5):
    """Run a simple load test with multiple clients"""

    print("\n" + "=" * 60)
    print(f"Load Test: {num_clients} clients, {num_requests} requests each")
    print("=" * 60)

    async def client_task(client_id):
        client = WebSocketClient("ws://localhost:8765")

        if not await client.connect():
            print(f"Client {client_id}: Failed to connect")
            return

        for i in range(num_requests):
            query = f"Test query {i+1} from client {client_id}"
            result = await client.send_route_request(query)
            if result:
                print(f"Client {client_id}: Request {i+1} -> {result.get('result')}")
            await asyncio.sleep(0.1)

        await client.close()
        print(f"Client {client_id}: Completed")

    start_time = time.time()
    await asyncio.gather(*[client_task(i) for i in range(num_clients)])
    elapsed = time.time() - start_time

    total_requests = num_clients * num_requests
    print("\n" + "=" * 60)
    print(f"Load Test Complete!")
    print(f"Total Requests: {total_requests}")
    print(f"Time Elapsed: {elapsed:.2f}s")
    print(f"Requests/Second: {total_requests/elapsed:.2f}")
    print("=" * 60)


async def main():
    """Main test runner"""
    if len(sys.argv) > 1 and sys.argv[1] == "--load":
        await load_test()
    else:
        success = await run_tests()

        if success and len(sys.argv) > 1 and sys.argv[1] == "--full":
            print("\nRunning load test...")
            await asyncio.sleep(2)
            await load_test()

        sys.exit(0 if success else 1)


if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("\n\nTest interrupted by user")
        sys.exit(1)
