<content>"""
WebSocket Server Configuration
Centralized configuration for the WebSocket server
"""

import os
from typing import Optional


class WebSocketConfig:
    """Configuration settings for WebSocket server"""

    # Server Settings
    HOST: str = os.getenv("WS_HOST", "localhost")
    PORT: int = int(os.getenv("WS_PORT", "8765"))

    # Performance Settings
    MAX_CONNECTIONS: int = int(os.getenv("WS_MAX_CONNECTIONS", "100"))
    MESSAGE_SIZE_LIMIT: int = int(os.getenv("WS_MESSAGE_SIZE_LIMIT", "1048576"))  # 1MB
    PING_INTERVAL: int = int(os.getenv("WS_PING_INTERVAL", "20"))  # seconds
    PING_TIMEOUT: int = int(os.getenv("WS_PING_TIMEOUT", "10"))  # seconds

    # Broadcast Settings
    STATUS_BROADCAST_INTERVAL: int = int(os.getenv("WS_STATUS_INTERVAL", "30"))  # seconds
    ENABLE_BROADCASTS: bool = os.getenv("WS_ENABLE_BROADCASTS", "true").lower() == "true"

    # Logging Settings
    LOG_LEVEL: str = os.getenv("WS_LOG_LEVEL", "INFO")
    LOG_FILE: Optional[str] = os.getenv("WS_LOG_FILE")  # None for stdout
    LOG_FORMAT: str = "%(asctime)s - %(name)s - %(levelname)s - %(message)s"

    # Security Settings (for future implementation)
    ENABLE_AUTH: bool = os.getenv("WS_ENABLE_AUTH", "false").lower() == "true"
    AUTH_TOKEN: Optional[str] = os.getenv("WS_AUTH_TOKEN")
    ENABLE_RATE_LIMIT: bool = os.getenv("WS_ENABLE_RATE_LIMIT", "false").lower() == "true"
    RATE_LIMIT_REQUESTS: int = int(os.getenv("WS_RATE_LIMIT_REQUESTS", "60"))  # per minute

    # CORS Settings
    ALLOWED_ORIGINS: list = os.getenv("WS_ALLOWED_ORIGINS", "*").split(",")

    # Router Settings
    ROUTER_MODEL_PATH: Optional[str] = os.getenv("WS_ROUTER_MODEL_PATH", "models/router_model.pth")
    USE_NEURAL_ROUTER: bool = os.getenv("WS_USE_NEURAL_ROUTER", "true").lower() == "true"

    @classmethod
    def to_dict(cls) -> dict:
        """Convert configuration to dictionary"""
        return {
            key: getattr(cls, key)
            for key in dir(cls)
            if not key.startswith("_") and key.isupper()
        }

    @classmethod
    def print_config(cls):
        """Print current configuration"""
        print("=" * 60)
        print("WebSocket Server Configuration")
        print("=" * 60)
        for key, value in cls.to_dict().items():
            print(f"{key:<30} = {value}")
        print("=" * 60)


# Configuration presets
class DevelopmentConfig(WebSocketConfig):
    """Development environment configuration"""
    HOST = "localhost"
    PORT = 8765
    LOG_LEVEL = "DEBUG"
    ENABLE_AUTH = False
    ENABLE_RATE_LIMIT = False


class ProductionConfig(WebSocketConfig):
    """Production environment configuration"""
    HOST = "0.0.0.0"
    PORT = 8765
    LOG_LEVEL = "INFO"
    LOG_FILE = "/var/log/irs-websocket.log"
    ENABLE_AUTH = True
    ENABLE_RATE_LIMIT = True
    MAX_CONNECTIONS = 1000
    ALLOWED_ORIGINS = ["https://yourdomain.com"]


class TestingConfig(WebSocketConfig):
    """Testing environment configuration"""
    HOST = "localhost"
    PORT = 8766  # Different port for testing
    LOG_LEVEL = "WARNING"
    ENABLE_AUTH = False
    ENABLE_BROADCASTS = False


# Load configuration based on environment
def get_config() -> WebSocketConfig:
    """Get configuration based on environment variable"""
    env = os.getenv("WS_ENV", "development").lower()

    configs = {
        "development": DevelopmentConfig,
        "production": ProductionConfig,
        "testing": TestingConfig,
    }

    config_class = configs.get(env, DevelopmentConfig)
    return config_class()


if __name__ == "__main__":
    # Print current configuration
    config = get_config()
    config.print_config()
</content>
